 64→export async function importProjectFile(file) {
 65→  if (!file) {
 66→    throw new Error('No project file selected.');
 67→  }
 68→
 69→  let json;
 70→  try {
 71→    json = JSON.parse(await file.text());
 72→  } catch {
 73→    throw new Error('Selected file is not valid JSON.');
 74→  }
